  ('dietitian-moex-11173', 'dietitian', 'dietitian-moex-093-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '有關兒童食物攝取之敘述，何者有誤？ 學齡期的兒童，飲食攝取易受到同儕之影響 學齡前的兒童十分好動，對食物的興趣容易轉移，當飢餓、食慾降低時，可以給予體積小熱量高的食物 兒童為引起家長的注意而拒吃，最好的方法是準備他喜歡吃的食物及家長的陪伴，避免兒童用拒吃作為武器 若兒童不吃食物，可以長期給予獎懲或壓力，鼓勵小孩食用', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "efc472ece55e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
